import React, { useState, useEffect, useRef } from 'react';

// A small internal component for the Sleep/Appetite slider
const MoodSlider = ({ value, onChange, labelLeft, labelRight }) => {
  return (
    <div style={{ width: '100%', maxWidth: '500px', margin: '40px auto' }}>
      <input
        type="range"
        min="0"
        max="100"
        value={value}
        onChange={(e) => onChange(e.target.value)}
        style={{
          width: '100%',
          height: '8px',
          appearance: 'none',
          background: '#e2e8f0',
          borderRadius: '10px',
          outline: 'none',
          cursor: 'pointer'
        }}
      />
      <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: '20px' }}>
        <span style={{ fontSize: '14px', color: '#94a3b8', fontWeight: '600' }}>{labelLeft}</span>
        <span style={{ fontSize: '14px', color: '#94a3b8', fontWeight: '600' }}>{labelRight}</span>
      </div>
    </div>
  );
};

const InputArea = ({ currentStep, onSendMessage, isTyping }) => {
  const [inputValue, setInputValue] = useState('');
  const inputRef = useRef(null);

  useEffect(() => {
    if (!isTyping && inputRef.current) inputRef.current.focus();
    // Reset internal input value when step changes
    if (currentStep?.type === 'slider') setInputValue(50);
    else setInputValue('');
  }, [currentStep, isTyping]);

  const handleSubmit = (e) => {
    e.preventDefault();
    if (inputValue.toString().trim() && !isTyping) {
      onSendMessage(inputValue);
    }
  };

  if (!currentStep || isTyping) return null;

  return (
    <div style={{ width: '100%', display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
      {/* TEXT & VOICE INPUT */}
      {(currentStep.type === 'text' || currentStep.type === 'voice_text') && (
        <form onSubmit={handleSubmit} style={{ width: '100%', textAlign: 'center' }}>
          <input
            ref={inputRef}
            placeholder="Type your answer..."
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
          />
          <button type="submit">Continue</button>
          {currentStep.type === 'voice_text' && (
            <p style={{ color: '#10b981', fontSize: '12px', marginTop: '10px', cursor: 'pointer' }}>
              🎤 Click to use Voice Recording
            </p>
          )}
        </form>
      )}

      {/* CHOICE INPUT */}
      {currentStep.type === 'choice' && (
        <div className="choice-container">
          {currentStep.options.map(option => (
            <button key={option} className="choice-btn" onClick={() => onSendMessage(option)}>
              {option}
            </button>
          ))}
        </div>
      )}

      {/* SLIDER INPUT (Biologicals) */}
      {currentStep.type === 'slider' && (
        <div style={{ width: '100%', textAlign: 'center' }}>
          <MoodSlider 
            value={inputValue} 
            onChange={setInputValue} 
            labelLeft={currentStep.labels[0]} 
            labelRight={currentStep.labels[1]} 
          />
          <button onClick={() => onSendMessage(inputValue)}>Confirm & Continue</button>
        </div>
      )}
    </div>
  );
};

export default InputArea;
